-- Session 4 — list_canonical_stages_with_works: full browse tree for the
-- estimate constructor's "Сметы" tab.
--
--   list_canonical_stages_with_works(p_template_id default null)
--     p_template_id NULL → the rovno.ai canonical (system) template.
--     Returns jsonb { template, stages:[ { works:[ { resource_lines:[] } ] } ] }.
--
-- This is intentionally close to get_estimate_template_detail, but tailored to
-- the constructor:
--   * defaults to the singleton system template when no id is given;
--   * exposes system_stage_article_id / system_work_article_id alongside the
--     template_stage_id / template_work_id so the UI can both apply (template id)
--     and link/label the canonical article (article id) on the same row;
--   * carries work_count / resource_count for the collapsed checkbox rows.
--
-- The constructor checkboxes operate on template ids: a checked stage is applied
-- via apply_template_stage_to_estimate(template_stage_id); a single checked work
-- via add_library_work_to_estimate(..., template_work_id).
--
-- Payload note: for the rovno.ai template this returns all 30 stages / 692 works
-- / ~5.9K resource lines as one jsonb document (same shape + size as the
-- existing get_estimate_template_detail, which is already consumed by the /home
-- estimates tab). If this proves heavy for the side panel, a future revision can
-- drop `resource_lines` here and lazy-load them per work.
--
-- Authorization: gated by can_read_template (true for the system template).
-- Returns NULL when the template does not exist OR the caller cannot read it
-- (keeps not-found vs forbidden opaque), matching get_estimate_template_detail.

create or replace function public.list_canonical_stages_with_works(
  p_template_id uuid default null
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_template_id uuid;
  v_owner_kind text;
  v_owner_id uuid;
begin
  if p_template_id is null then
    select id, owner_kind, owner_id
      into v_template_id, v_owner_kind, v_owner_id
    from public.estimate_templates
    where owner_kind = 'system'
    limit 1;
  else
    select id, owner_kind, owner_id
      into v_template_id, v_owner_kind, v_owner_id
    from public.estimate_templates
    where id = p_template_id;
  end if;

  if v_template_id is null then
    return null;
  end if;
  if not public.can_read_template(v_owner_kind, v_owner_id) then
    return null;
  end if;

  return jsonb_build_object(
    'template', (
      select jsonb_build_object(
        'id', et.id,
        'title', et.title,
        'owner_kind', et.owner_kind,
        'scope', et.scope
      )
      from public.estimate_templates et
      where et.id = v_template_id
    ),
    'stages', (
      select coalesce(jsonb_agg(stage_obj order by sort_hint, title), '[]'::jsonb)
      from (
        select
          ts.sort_hint,
          ts.title,
          jsonb_build_object(
            'template_stage_id', ts.id,
            'system_stage_article_id', ts.system_stage_article_id,
            'title', ts.title,
            'description', ts.description,
            'sort_hint', ts.sort_hint,
            'work_count', (
              select count(*)::int
              from public.template_works tw
              where tw.template_stage_id = ts.id
            ),
            'resource_count', (
              select count(*)::int
              from public.template_resource_lines trl
              join public.template_works tw2 on tw2.id = trl.template_work_id
              where tw2.template_stage_id = ts.id
            ),
            'works', (
              select coalesce(jsonb_agg(work_obj order by sort_hint, title), '[]'::jsonb)
              from (
                select
                  tw.sort_hint,
                  tw.title,
                  jsonb_build_object(
                    'template_work_id', tw.id,
                    'system_work_article_id', tw.system_work_article_id,
                    'title', tw.title,
                    'description', tw.description,
                    'sort_hint', tw.sort_hint,
                    'resource_count', (
                      select count(*)::int
                      from public.template_resource_lines trl3
                      where trl3.template_work_id = tw.id
                    ),
                    'resource_lines', (
                      select coalesce(jsonb_agg(line_obj order by sort_hint, title), '[]'::jsonb)
                      from (
                        select
                          trl.sort_hint,
                          trl.title,
                          jsonb_build_object(
                            'id', trl.id,
                            'title', trl.title,
                            'resource_type', trl.resource_type,
                            'unit_display', trl.unit_display,
                            'qty_default', trl.qty_default,
                            'default_cost_unit_cents', trl.default_cost_unit_cents,
                            'system_resource_article_id', trl.system_resource_article_id,
                            'sort_hint', trl.sort_hint
                          ) as line_obj
                        from public.template_resource_lines trl
                        where trl.template_work_id = tw.id
                      ) lines
                    )
                  ) as work_obj
                from public.template_works tw
                where tw.template_stage_id = ts.id
              ) works
            )
          ) as stage_obj
        from public.template_stages ts
        where ts.estimate_template_id = v_template_id
      ) stages
    )
  );
end;
$$;

revoke all on function public.list_canonical_stages_with_works(uuid) from public;
grant execute on function public.list_canonical_stages_with_works(uuid) to authenticated;
